// Mock streaming implementation
fn process_chunk(chunk: &str) -> Result<&str, StreamError> {
    // BUG: Assumes all chunks are valid UTF-8
    // If chunk contains invalid bytes, this panics
    Ok(std::str::from_utf8(chunk.as_bytes())?)
}

enum StreamError {
    InvalidUtf8,
    MalformedToken,
}
